# Memory Leaking in Rust with `Box::leak`

## The Function and Explanation

```rust
use std::collections::HashMap;
use std::sync::OnceLock;

// ============================================================
// Example 1: Static configuration loaded once at startup
// ============================================================

#[derive(Debug)]
pub struct AppConfig {
    pub database_url: String,
    pub max_connections: u32,
    pub feature_flags: HashMap<String, bool>,
}

impl AppConfig {
    pub fn new(database_url: &str, max_connections: u32) -> Self {
        let mut feature_flags = HashMap::new();
        feature_flags.insert("dark_mode".to_string(), true);
        feature_flags.insert("beta_features".to_string(), false);

        AppConfig {
            database_url: database_url.to_string(),
            max_connections,
            feature_flags,
        }
    }
}

/// Leaks a config struct to get a `&'static` reference.
/// 
/// # When this is appropriate:
/// - The value must live for the entire program duration
/// - You need a `&'static` reference (e.g., for thread spawning without Arc)
/// - The allocation happens ONCE at startup (not in a loop)
/// - The data is genuinely global and immutable after initialization
pub fn leak_config(config: AppConfig) -> &'static AppConfig {
    Box::leak(Box::new(config))
}

// ============================================================
// Example 2: Static string slices from dynamic data
// ============================================================

/// Convert a runtime String into a &'static str.
/// 
/// Useful when an API requires &'static str but you're building
/// the string at runtime (e.g., from env vars or config files).
pub fn leak_string(s: String) -> &'static str {
    Box::leak(s.into_boxed_str())
}

